let todolist,tododate,todoitems,dailyfocus,day=(new Date).getDay();function todoInit(){todolist=document.getElementById("todolist"),tododate=document.getElementById("tododate"),dailyfocus=document.getElementById("focus"),todoitems={monday:[["study","work","walk"],"productivity"],tuesday:[["study","exercise"],"productivity, phyiscal health"],wednesday:[["meditate","read"],"mindfulness"],thursday:[["walk"],"life satisfaction"],friday:[["creative writing","meditate"],"mindfulness"],saturday:[["update todo","budgeting"],"future"],sunday:[["study","work","exercise","read"],"productivity"]},updateDay()}function updateDay(){let t=["sunday","monday","tuesday","wednesday","thursday","friday","saturday"][day],e=todoitems[t];todolist.innerHTML="",tododate.innerHTML='<span onclick="changeDay(-1);">&lt</span> '+t+' <span onclick="changeDay(1);">&gt</span>';let d=document.createDocumentFragment();for(let t=0;t<e[0].length;t++){let a=document.createElement("p");a.innerText=e[0][t],a.addEventListener("click",function(){""===a.style.textDecoration?a.style.textDecoration="line-through":a.style.textDecoration=""},!1),d.appendChild(a)}todolist.appendChild(d),dailyfocus.innerHTML="<i> <u>focus:</u> "+e[1]+"</i>"}function changeDay(t){(day+=t)<0&&(day=6),day>6&&(day=0),updateDay()}todoInit();
